32	#define TLB_SETS 16
33	#define TLB_WAYS 4
34	#define PAGE_SIZE 0x1000u
35	#define ROUND_TO_PAGE(addr) ((addr) & ~(PAGE_SIZE - 1u))
36	#define PAGE_OFFSET(addr) ((addr) & (PAGE_SIZE - 1u))
37	#define TRAP_LEVELS 2
38	
39	#ifdef DUMP_INSTRUCTION_STATS
40	#define TALLY_INSTRUCTION(type) thread->core->proc->stat ## type++
41	#else
42	#define TALLY_INSTRUCTION(type) do { } while (0)
43	#endif
44	
45	#define INVALID_ADDR 0xfffffffful
46	
47	// When a breakpoint is set, this instruction replaces the one at the
48	// breakpoint address. It is invalid, because it uses a reserved format
49	// type. The interpreter only performs a breakpoint lookup when it sees
50	// this instruction (instead of for every instruction it executes) as an
51	// optimization. This is different than the native 'breakpoint' instruction.
52	#define BREAKPOINT_INST 0x707fffff
53	
54	struct thread
55	{
56	    struct core *core;
57	    uint32_t id;
58	    uint32_t last_sync_load_addr; // Cache line number (addr / 64)
59	    uint32_t pc;
60	    uint32_t asid;
61	    uint32_t page_dir;
62	    uint32_t interrupt_mask;
63	    uint32_t latched_interrupts;
64	    bool enable_interrupt;
65	    bool enable_mmu;
66	    bool enable_supervisor;
67	    uint32_t subcycle;
68	    uint32_t scalar_reg[NUM_REGISTERS];
69	    uint32_t vector_reg[NUM_REGISTERS][NUM_VECTOR_LANES];
70	
71	    // There are two levels of trap information, to handle a nested TLB
72	    // miss occurring in the middle of another trap.
73	    struct
74	    {
75	        uint32_t trap_cause;
76	        uint32_t pc;
77	        uint32_t access_address;
78	        uint32_t scratchpad0;
79	        uint32_t scratchpad1;
80	        uint32_t subcycle;
81	        uint32_t syscall_index;
82	        bool enable_interrupt;
83	        bool enable_mmu;
84	        bool enable_supervisor;
85	    } saved_trap_state[TRAP_LEVELS];
86	};
87	
88	struct tlb_entry
89	{
90	    uint32_t asid;
91	    uint32_t virtual_address;
92	    uint32_t phys_addr_and_flags;
93	};
94	
95	struct core
96	{
97	    struct processor *proc;
98	    struct thread *threads;
99	    uint32_t trap_handler_pc;
100	    uint32_t tlb_miss_handler_pc;
101	    uint32_t phys_tlb_update_addr;
102	    uint32_t is_level_triggered;    // Bitmap
103	    struct tlb_entry *itlb;
104	    uint32_t next_itlb_way;
105	    struct tlb_entry *dtlb;
106	    uint32_t next_dtlb_way;
107	};
108	
109	struct processor
110	{
111	    uint32_t total_threads;
112	    uint32_t thread_enable_mask;
113	    uint32_t num_cores;
114	    uint32_t threads_per_core;
115	    struct core *cores;
116	    struct breakpoint *breakpoints;
117	    uint32_t *memory;
118	    uint32_t memory_size;
119	    uint32_t interrupt_levels;
120	    bool random_thread_sched;
121	    bool crashed;
122	    bool single_stepping;
123	    bool stop_on_fault;
124	    bool enable_tracing;
125	    bool enable_cosim;
126	#ifdef DUMP_INSTRUCTION_STATS
127	    int64_t stat_vector_inst;
128	    int64_t stat_load_inst;
129	    int64_t stat_store_inst;
130	    int64_t stat_branch_inst;
131	    int64_t stat_imm_arith_inst;
132	    int64_t stat_reg_arith_inst;
133	#endif
134	    uint32_t current_timer_count;
135	    int64_t total_instructions;
136	};
137	
138	struct breakpoint
139	{
140	    struct breakpoint *next;
141	    uint32_t address;
142	    uint32_t original_instruction;
143	    bool restart;
144	};
