146	static inline const struct thread *get_const_thread(const struct processor *proc, uint32_t thread_id);
147	static inline struct thread *get_thread(struct processor *proc, uint32_t thread_id);
148	static void print_thread_registers(const struct thread*);
149	static void set_scalar_reg(struct thread*, uint32_t reg, uint32_t value);
150	static void set_vector_reg(struct thread*, uint32_t reg, uint32_t mask,
151	                           uint32_t *values);
