157	                       bool is_data_cache, uint32_t syscall_index);
158	
159	// Translate addresses using the translation lookaside buffer. Returns true
160	// if there was a valid translation, false otherwise (in the latter case, it
161	// will also raise a trap or print an error as a side effect).
162	static bool translate_address(struct thread*, uint32_t virtual_address, uint32_t
163	                              *physical_address, bool is_store, bool is_data_cache);
164	static uint32_t scalar_arithmetic_op(enum arithmetic_op, uint32_t value1, uint32_t value2);
165	static bool is_compare_op(uint32_t op);
