167	static void execute_register_arith_inst(struct thread*, uint32_t instruction);
168	static void execute_immediate_arith_inst(struct thread*, uint32_t instruction);
169	static void execute_scalar_load_store_inst(struct thread*, uint32_t instruction);
170	static void execute_block_load_store_inst(struct thread*, uint32_t instruction);
171	static void execute_scatter_gather_inst(struct thread*, uint32_t instruction);
172	static void execute_control_register_inst(struct thread*, uint32_t instruction);
173	static void read_control_register(struct thread*, uint32_t cr_index,
174	                                  uint32_t dst_src_reg);
175	static void write_control_register(struct thread*, uint32_t cr_index,
176	                                   uint32_t dst_src_reg);
177	static void execute_memory_access_inst(struct thread*, uint32_t instruction);
178	static void execute_branch_inst(struct thread*, uint32_t instruction);
179	static void execute_cache_control_inst(struct thread*, uint32_t instruction);
180	
181	// Returns false if this hit a breakpoint and should break out of execution
182	// loop.
183	static bool execute_instruction(struct thread*);
184	static void timer_tick(struct processor *proc);
185	
186	struct processor *init_processor(uint32_t memory_size, uint32_t num_cores,
187	                                 uint32_t threads_per_core, bool randomize_memory,
188	                                 const char *shared_memory_file)
189	{
190	    uint32_t address;
191	    uint32_t thread_id;
192	    uint32_t core_id;
193	    struct processor *proc;
194	    struct core *core;
195	    int i;
196	    int shared_memory_fd;
197	
198	    // Limited by enable mask
199	    assert(num_cores * threads_per_core <= 32);
200	
201	    proc = (struct processor*) calloc(sizeof(struct processor), 1);
202	    proc->memory_size = memory_size;
203	    if (shared_memory_file != NULL)
204	    {
205	        shared_memory_fd = open(shared_memory_file, O_CREAT | O_RDWR, 666);
206	        if (shared_memory_fd < 0)
207	        {
208	            perror("init_processor: Error opening shared memory file");
209	            free(proc);
210	            return NULL;
211	        }
212	
213	        if (ftruncate(shared_memory_fd, memory_size) < 0)
214	        {
215	            perror("init_processor: couldn't resize shared memory file");
216	            free(proc);
217	            return NULL;
218	        }
219	
220	        proc->memory = mmap(NULL, memory_size, PROT_READ | PROT_WRITE, MAP_SHARED
221	                            | MAP_FILE, shared_memory_fd, 0);
222	        if (proc->memory == NULL)
223	        {
224	            perror("init_processor: mmap failed");
225	            free(proc);
226	            return NULL;
227	        }
228	    }
229	    else
230	    {
231	        proc->memory = (uint32_t*) malloc(memory_size);
232	        if (proc->memory == NULL)
233	        {
234	            perror("init_processor: malloc failed");
235	            free(proc);
236	            return NULL;
237	        }
238	
239	        if (randomize_memory)
240	        {
241	            for (address = 0; address < memory_size / 4; address++)
242	                proc->memory[address] = (uint32_t) next_random();
243	        }
244	        else
245	            memset(proc->memory, 0, proc->memory_size);
246	    }
247	
248	    proc->cores = (struct core*) calloc(sizeof(struct core), num_cores);
249	    for (core_id = 0; core_id < num_cores; core_id++)
250	    {
251	        core = &proc->cores[core_id];
252	        core->proc = proc;
253	        core->itlb = (struct tlb_entry*) malloc(sizeof(struct tlb_entry) * TLB_SETS * TLB_WAYS);
254	        core->dtlb = (struct tlb_entry*) malloc(sizeof(struct tlb_entry) * TLB_SETS * TLB_WAYS);
255	        for (i = 0; i < TLB_SETS * TLB_WAYS; i++)
256	        {
257	            // Set to invalid (unaligned) addresses so these don't match
258	            core->itlb[i].virtual_address = INVALID_ADDR;
259	            core->dtlb[i].virtual_address = INVALID_ADDR;
260	        }
261	
262	        core->threads = (struct thread*) calloc(sizeof(struct thread), threads_per_core);
263	        for (thread_id = 0; thread_id < threads_per_core; thread_id++)
264	        {
265	            core->threads[thread_id].core = core;
266	            core->threads[thread_id].id = core_id * threads_per_core + thread_id;
267	            core->threads[thread_id].last_sync_load_addr = INVALID_ADDR;
268	            core->threads[thread_id].enable_supervisor = true;
269	            core->threads[thread_id].saved_trap_state[0].enable_supervisor = true;
270	        }
271	
272	        core->trap_handler_pc = 0;
273	    }
274	
275	    proc->total_threads = threads_per_core * num_cores;
276	    proc->threads_per_core = threads_per_core;
277	    proc->num_cores = num_cores;
278	    proc->thread_enable_mask = 1;
279	
280	    return proc;
281	}
282	
283	void enable_tracing(struct processor *proc)
284	{
285	    proc->enable_tracing = true;
286	}
287	
288	void enable_random_thread_sched(struct processor *proc)
289	{
290	    proc->random_thread_sched = true;
291	}
292	
293	int load_hex_file(struct processor *proc, const char *filename)
294	{
295	    return read_hex_file(filename, proc->memory, proc->memory_size);
296	}
297	
298	void write_memory_to_file(const struct processor *proc, const char *filename,
299	                          uint32_t base_address, uint32_t length)
300	{
301	    FILE *file;
302	
303	    file = fopen(filename, "wb+");
304	    if (file == NULL)
305	    {
306	        perror("write_memory_to_file: Error opening output file");
307	        return;
308	    }
309	
310	    if (fwrite((int8_t*) proc->memory + base_address, MIN(proc->memory_size, length), 1, file) != 1)
311	    {
312	        fclose(file);
313	        perror("write_memory_to_file: fwrite failed");
314	        return;
315	    }
316	
317	    fclose(file);
318	}
319	
320	const void *get_memory_region_ptr(const struct processor *proc, uint32_t address, uint32_t length)
321	{
322	    assert(length < proc->memory_size);
323	
324	    // Prevent overrun for bad address
325	    if (address > proc->memory_size || address + length > proc->memory_size)
326	        return proc->memory;
327	
328	    return ((const uint8_t*) proc->memory) + address;
329	}
330	
331	void print_registers(const struct processor *proc, uint32_t thread_id)
332	{
333	    print_thread_registers(get_const_thread(proc, thread_id));
