341	void raise_interrupt(struct processor *proc, uint32_t int_bitmap)
342	{
343	    uint32_t thread_id;
344	    uint32_t core_id;
345	    struct core *core;
346	    struct thread *thread;
347	
348	    proc->interrupt_levels |= int_bitmap;
349	    for (core_id = 0; core_id < proc->num_cores; core_id++)
350	    {
351	        core = &proc->cores[core_id];
352	        for (thread_id = 0; thread_id < proc->threads_per_core; thread_id++)
353	        {
354	            thread = &core->threads[thread_id];
355	            thread->latched_interrupts |= int_bitmap;
356	            try_to_dispatch_interrupt(thread);
357	        }
358	    }
359	}
