366	void cosim_interrupt(struct processor *proc, uint32_t thread_id, uint32_t pc)
367	{
368	    struct thread *thread = get_thread(proc, thread_id);
369	
370	    // This handles an edge case where cosimulation mismatches would occur
371	    // if an interrupt happened during a scatter store. Hardware does not
372	    // create store cycles for scatter store lanes that do not have the mask
373	    // bit set (and thus doesn't emit cosimulation events). It's possible for
374	    // the instruction to finish in hardware, but the emulator not to have
375	    // finished it. When it starts executing the ISR, the subcycle counter
376	    // will be non-zero, which messes up things later.
377	    if (pc != thread->pc)
378	        thread->subcycle = 0;
379	
380	    thread->pc = pc;
381	    thread->latched_interrupts |= INT_COSIM;
382	    try_to_dispatch_interrupt(thread);
383	}
