400	bool execute_instructions(struct processor *proc, uint64_t total_instructions)
401	{
402	    uint64_t instruction_count;
403	    uint32_t next_thread = 0;
404	
405	    proc->single_stepping = false;
406	    if (proc->random_thread_sched)
407	    {
408	        for (instruction_count = 0; instruction_count < total_instructions;
409	            instruction_count++)
410	        {
411	            if (proc->thread_enable_mask == 0)
412	            {
413	                printf("thread enable mask is now zero\n");
414	                return false;
415	            }
416	
417	            if (proc->crashed)
418	                return false;
419	
420	            next_thread = next_set_bit(proc->thread_enable_mask,
421	                (uint32_t) next_random() % proc->total_threads);
422	            if (!execute_instruction(get_thread(proc, next_thread)))
423	                return false;  // Hit breakpoint
424	
425	            timer_tick(proc);
426	        }
427	    }
428	    else
429	    {
430	        // Round robin execution (faster than random execution)
431	        for (instruction_count = 0; instruction_count < total_instructions;
432	            instruction_count++)
433	        {
434	            if (proc->thread_enable_mask == 0)
435	            {
436	                printf("thread enable mask is now zero\n");
437	                return false;
438	            }
439	
440	            if (proc->crashed)
441	                return false;
442	
443	            next_thread = next_set_bit(proc->thread_enable_mask,
444	                ((next_thread + 31) & 31));
445	            if (!execute_instruction(get_thread(proc, next_thread)))
446	                return false;  // Hit breakpoint
447	
448	            timer_tick(proc);
449	        }
450	    }
451	
452	    return true;
453	}
