511	int dbg_set_breakpoint(struct processor *proc, uint32_t pc)
512	{
513	    struct breakpoint *breakpoint = lookup_breakpoint(proc, pc);
514	    if (breakpoint != NULL)
515	    {
516	        printf("already has a breakpoint at address %x\n", pc);
517	        return -1;
518	    }
519	
520	    if (pc >= proc->memory_size || (pc & 3) != 0)
521	    {
522	        printf("invalid breakpoint address %x\n", pc);
523	        return -1;
524	    }
525	
526	    breakpoint = (struct breakpoint*) calloc(sizeof(struct breakpoint), 1);
527	    breakpoint->next = proc->breakpoints;
528	    proc->breakpoints = breakpoint;
529	    breakpoint->address = pc;
530	    breakpoint->original_instruction = proc->memory[pc / 4];
531	    if (breakpoint->original_instruction == BREAKPOINT_INST)
532	        breakpoint->original_instruction = INSTRUCTION_NOP;	// Avoid infinite loop
533	
534	    proc->memory[pc / 4] = BREAKPOINT_INST;
535	    return 0;
536	}
