538	int dbg_clear_breakpoint(struct processor *proc, uint32_t pc)
539	{
540	    struct breakpoint **link;
541	    struct breakpoint *breakpoint;
542	
543	    for (link = &proc->breakpoints; *link; link = &(*link)->next)
544	    {
545	        breakpoint = *link;
546	        if (breakpoint->address == pc)
547	        {
548	            proc->memory[pc / 4] = breakpoint->original_instruction;
549	            *link = breakpoint->next;
550	            free(breakpoint);
551	            return 0;
552	        }
553	    }
554	
555	    return -1; // Not found
556	}
