685	static void try_to_dispatch_interrupt(struct thread *thread)
686	{
687	    uint32_t pending = get_pending_interrupts(thread);
688	    if (!thread->enable_interrupt)
689	        return;
690	
691	    if ((pending & thread->interrupt_mask) != 0)
692	    {
693	        // Unlike exceptions, an interrupt saves the PC of the *next* instruction,
694	        // rather than the current one, but only if a multicycle instruction is
695	        // not active. Advance the PC here accordingly.
696	        if (thread->subcycle == 0)
697	            thread->pc += 4;
698	
699	        raise_trap(thread, 0, TT_INTERRUPT, false, false, 0);
700	    }
701	}
