703	static uint32_t get_pending_interrupts(struct thread *thread)
704	{
705	    return (thread->core->is_level_triggered & thread->core->proc->interrupt_levels)
706	           | (~thread->core->is_level_triggered & thread->latched_interrupts);
707	}
