709	static const char *get_trap_name(enum trap_type type)
710	{
711	#define TRAP_ENTRY(x)  case TT_ ## x: return #x;
712	    switch (type)
713	    {
714	        TRAP_ENTRY(RESET)
715	        TRAP_ENTRY(ILLEGAL_INSTRUCTION)
716	        TRAP_ENTRY(PRIVILEGED_OP)
717	        TRAP_ENTRY(INTERRUPT)
718	        TRAP_ENTRY(SYSCALL)
719	        TRAP_ENTRY(UNALIGNED_ACCESS)
720	        TRAP_ENTRY(PAGE_FAULT)
721	        TRAP_ENTRY(TLB_MISS)
722	        TRAP_ENTRY(ILLEGAL_STORE)
723	        TRAP_ENTRY(SUPERVISOR_ACCESS)
724	        TRAP_ENTRY(NOT_EXECUTABLE)
725	        TRAP_ENTRY(BREAKPOINT)
726	        default:
727	            return "???";
728	    }
729	#undef TRAP_ENTRY
730	}
731	
732	static void raise_trap(struct thread *thread, uint32_t trap_address, enum trap_type type,
733	                       bool is_store, bool is_data_cache, uint32_t syscall_index)
734	{
735	    if (thread->core->proc->enable_tracing)
736	    {
737	        printf("%08x [th %u] trap %d store %d cache %d %08x index %u\n",
738	               thread->pc - 4, thread->id, type, is_store, is_data_cache,
739	               trap_address, syscall_index);
740	    }
741	
742	    if ((thread->core->proc->stop_on_fault || thread->core->trap_handler_pc == 0)
743	            && type != TT_TLB_MISS
744	            && type != TT_INTERRUPT
745	            && type != TT_SYSCALL)
746	    {
747	        thread->pc -= 4;    // reset PC to faulting instruction
748	        printf("Thread %u caught fault %s @%08x\n", thread->id,
749	            get_trap_name(type), thread->pc);
750	        print_thread_registers(thread);
751	        thread->core->proc->crashed = true;
752	        return;
753	    }
754	
755	    // For nested interrupts, push the old saved state into
756	    // the second save slot.
757	    thread->saved_trap_state[1] = thread->saved_trap_state[0];
758	
759	    // Save current trap information
760	    thread->saved_trap_state[0].trap_cause = type | (is_store ? 0x10ul : 0)
761	            | (is_data_cache ? 0x20ul : 0);
762	
763	    // Kludge
764	    // In most cases, the PC points to the next instruction after the one
765	    // that is currently executing. The trap PC should point to the one
766	    // that was trapped on, so we decrement it here. However, a multi-cycle
767	    // instruction like load_gath resets the PC to the current instruction
768	    // after it executes. If an interrupt occurs, we need to avoid subtracting
769	    // four. Other traps types like alignment exceptions or page faults will
770	    // be raised before the PC is decremented in the scatter/gather routine,
771	    // so those should still decrement for those trap types.
772	    if (thread->subcycle != 0 && type == TT_INTERRUPT)
773	        thread->saved_trap_state[0].pc = thread->pc;
774	    else
775	        thread->saved_trap_state[0].pc = thread->pc - 4;
776	
777	    thread->saved_trap_state[0].enable_interrupt = thread->enable_interrupt;
778	    thread->saved_trap_state[0].enable_mmu = thread->enable_mmu;
779	    thread->saved_trap_state[0].enable_supervisor = thread->enable_supervisor;
780	    thread->saved_trap_state[0].subcycle = thread->subcycle;
781	    thread->saved_trap_state[0].access_address = trap_address;
782	    thread->saved_trap_state[0].syscall_index = syscall_index;
783	
784	    // Update thread state
785	    thread->enable_interrupt = false;
786	    if (type == TT_TLB_MISS)
787	    {
788	        thread->pc = thread->core->tlb_miss_handler_pc;
789	        thread->enable_mmu = false;
790	    }
791	    else
792	        thread->pc = thread->core->trap_handler_pc;
793	
794	    thread->subcycle = 0;
795	    thread->enable_supervisor = true;
796	}
797	
798	static bool translate_address(struct thread *thread, uint32_t virtual_address,
799	                              uint32_t *out_physical_address, bool is_store,
800	                              bool is_data_access)
801	{
802	    int tlb_set;
803	    int way;
804	    struct tlb_entry *set_entries;
805	
806	    if (!thread->enable_mmu)
807	    {
808	        if (virtual_address >= thread->core->proc->memory_size
809	            && virtual_address < DEVICE_BASE_ADDRESS)
810	        {
811	            // This isn't an actual fault supported by the hardware, but a debugging
812	            // aid only available in the emulator.
813	            printf("Memory access out of range %08x (MMU not enabled)\n",
814	                   virtual_address);
815	            print_thread_registers(thread);
816	            thread->core->proc->crashed = true;
817	            return false;
818	        }
819	
820	        *out_physical_address = virtual_address;
821	        return true;
822	    }
823	
824	    tlb_set = (virtual_address / PAGE_SIZE) % TLB_SETS;
825	    set_entries = (is_data_access ? thread->core->dtlb : thread->core->itlb)
826	                  + tlb_set * TLB_WAYS;
827	    for (way = 0; way < TLB_WAYS; way++)
828	    {
829	        if (set_entries[way].virtual_address == ROUND_TO_PAGE(virtual_address)
830	                && ((set_entries[way].phys_addr_and_flags & TLB_GLOBAL) != 0
831	                    || set_entries[way].asid == thread->asid))
832	        {
833	            if ((set_entries[way].phys_addr_and_flags & TLB_PRESENT) == 0)
834	            {
835	                raise_trap(thread, virtual_address, TT_PAGE_FAULT, is_store,
836	                           is_data_access, 0);
837	                return false;
838	            }
839	
840	            if ((set_entries[way].phys_addr_and_flags & TLB_SUPERVISOR) != 0
841	                    && !thread->enable_supervisor)
842	            {
843	                raise_trap(thread, virtual_address, TT_SUPERVISOR_ACCESS, is_store,
844	                           is_data_access, 0);
845	                return false;
846	            }
847	
848	            if ((set_entries[way].phys_addr_and_flags & TLB_EXECUTABLE) == 0
849	                    && !is_data_access)
850	            {
851	                raise_trap(thread, virtual_address, TT_NOT_EXECUTABLE, false,
852	                    false, 0);
853	                return false;
854	            }
855	
856	            if (is_store && (set_entries[way].phys_addr_and_flags & TLB_WRITE_ENABLE) == 0)
857	            {
858	                raise_trap(thread, virtual_address, TT_ILLEGAL_STORE, true,
859	                           is_data_access, 0);
860	                return false;
861	            }
862	
863	            *out_physical_address = ROUND_TO_PAGE(set_entries[way].phys_addr_and_flags)
864	                                    | PAGE_OFFSET(virtual_address);
865	
866	            if (*out_physical_address >= thread->core->proc->memory_size
867	                && *out_physical_address < DEVICE_BASE_ADDRESS)
868	            {
869	                // This isn't an actual fault supported by the hardware, but a debugging
870	                // aid only available in the emulator.
871	                printf("Translated physical address out of range. va %08x pa %08x\n",
872	                       virtual_address, *out_physical_address);
873	                print_thread_registers(thread);
874	                thread->core->proc->crashed = true;
875	                return false;
876	            }
877	
878	            return true;
879	        }
880	    }
881	
882	    // No translation found
883	    raise_trap(thread, virtual_address, TT_TLB_MISS, is_store, is_data_access, 0);
884	    return false;
885	}
