887	static uint32_t scalar_arithmetic_op(enum arithmetic_op operation, uint32_t value1, uint32_t value2)
888	{
889	    switch (operation)
890	    {
891	        case OP_OR:
892	            return value1 | value2;
893	        case OP_AND:
894	            return value1 & value2;
895	        case OP_XOR:
896	            return value1 ^ value2;
897	        case OP_ADD_I:
898	            return value1 + value2;
899	        case OP_SUB_I:
900	            return value1 - value2;
901	        case OP_MULL_I:
902	            return value1 * value2;
903	        case OP_MULH_U:
904	            return (uint32_t)(((uint64_t)value1 * (uint64_t)value2) >> 32);
905	        case OP_ASHR:
906	            return (uint32_t)(((int32_t)value1) >> (value2 & 31));
907	        case OP_SHR:
908	            return value1 >> (value2 & 31);
909	        case OP_SHL:
910	            return value1 << (value2 & 31);
911	        case OP_CLZ:
912	            return value2 == 0 ? 32u : (uint32_t)__builtin_clz(value2);
913	        case OP_CTZ:
914	            return value2 == 0 ? 32u : (uint32_t)__builtin_ctz(value2);
915	        case OP_MOVE:
916	            return value2;
917	        case OP_CMPEQ_I:
918	            return (uint32_t)value1 == value2;
919	        case OP_CMPNE_I:
920	            return (uint32_t)value1 != value2;
921	        case OP_CMPGT_I:
922	            return (uint32_t)((int32_t)value1 > (int32_t)value2);
923	        case OP_CMPGE_I:
924	            return (uint32_t)((int32_t)value1 >= (int32_t)value2);
925	        case OP_CMPLT_I:
926	            return (uint32_t)((int32_t)value1 < (int32_t)value2);
927	        case OP_CMPLE_I:
928	            return (uint32_t)((int32_t)value1 <= (int32_t)value2);
929	        case OP_CMPGT_U:
930	            return (uint32_t)(value1 > value2);
931	        case OP_CMPGE_U:
932	            return (uint32_t)(value1 >= value2);
933	        case OP_CMPLT_U:
934	            return (uint32_t)(value1 < value2);
935	        case OP_CMPLE_U:
936	            return (uint32_t)(value1 <= value2);
937	        case OP_FTOI:
938	            return (uint32_t)(int32_t)value_as_float(value2);
939	        case OP_RECIPROCAL:
940	        {
941	            // Reciprocal only has 6 bits of accuracy
942	            float fresult = 1.0f / value_as_float(value2 & 0xfffe0000);
943	            uint32_t iresult = value_as_int(fresult);
944	            if (!isnan(fresult))
945	                iresult &= 0xfffe0000;	// Truncate, but only if not NaN
946	
947	            return iresult;
948	        }
949	
950	        case OP_SEXT8:
951	            return (uint32_t)(int32_t)(int8_t)value2;
952	        case OP_SEXT16:
953	            return (uint32_t)(int32_t)(int16_t)value2;
954	        case OP_MULH_I:
955	            return (uint32_t) (((int64_t)(int32_t)value1 * (int64_t)(int32_t)value2) >> 32);
956	        case OP_ADD_F:
957	            return value_as_int(value_as_float(value1) + value_as_float(value2));
958	        case OP_SUB_F:
959	            return value_as_int(value_as_float(value1) - value_as_float(value2));
960	        case OP_MUL_F:
961	            return value_as_int(value_as_float(value1) * value_as_float(value2));
962	        case OP_ITOF:
963	            return value_as_int((float)(int32_t)value2);
964	        case OP_CMPGT_F:
965	            return value_as_float(value1) > value_as_float(value2);
966	        case OP_CMPGE_F:
967	            return value_as_float(value1) >= value_as_float(value2);
968	        case OP_CMPLT_F:
969	            return value_as_float(value1) < value_as_float(value2);
970	        case OP_CMPLE_F:
971	            return value_as_float(value1) <= value_as_float(value2);
972	        case OP_CMPEQ_F:
973	            return value_as_float(value1) == value_as_float(value2);
974	        case OP_CMPNE_F:
975	            return value_as_float(value1) != value_as_float(value2);
976	        default:
977	            return 0u;
978	    }
979	}
980	
981	static bool is_compare_op(uint32_t op)
982	{
983	    return (op >= OP_CMPEQ_I && op <= OP_CMPLE_U) || (op >= OP_CMPGT_F && op <= OP_CMPNE_F);
984	}
