986	static struct breakpoint *lookup_breakpoint(struct processor *proc, uint32_t pc)
987	{
988	    struct breakpoint *breakpoint;
989	
990	    for (breakpoint = proc->breakpoints; breakpoint; breakpoint =
991	                breakpoint->next)
992	    {
993	        if (breakpoint->address == pc)
994	            return breakpoint;
995	    }
996	
997	    return NULL;
998	}
