1000	static void execute_register_arith_inst(struct thread *thread, uint32_t instruction)
1001	{
1002	    enum register_arith_format fmt = extract_unsigned_bits(instruction, 26, 3);
1003	    enum arithmetic_op op = extract_unsigned_bits(instruction, 20, 6);
1004	    uint32_t op1reg = extract_unsigned_bits(instruction, 0, 5);
1005	    uint32_t op2reg = extract_unsigned_bits(instruction, 15, 5);
1006	    uint32_t destreg = extract_unsigned_bits(instruction, 5, 5);
1007	    uint32_t maskreg = extract_unsigned_bits(instruction, 10, 5);
1008	    int lane;
1009	
1010	    if (op == OP_BREAKPOINT)
1011	    {
1012	        raise_trap(thread, 0, TT_BREAKPOINT, false, false, 0);
1013	        return;
1014	    }
1015	
1016	    TALLY_INSTRUCTION(reg_arith_inst);
1017	    if (op == OP_GETLANE)
1018	    {
1019	        set_scalar_reg(thread, destreg, thread->vector_reg[op1reg]
1020	                       [thread->scalar_reg[op2reg] & 0xf]);
1021	    }
1022	    else if (is_compare_op(op))
1023	    {
1024	        uint32_t result = 0;
1025	        switch (fmt)
1026	        {
1027	            case FMT_RA_SS:
1028	                result = scalar_arithmetic_op(op, thread->scalar_reg[op1reg],
1029	                                              thread->scalar_reg[op2reg]) ? 0xffff : 0;
1030	                break;
1031	
1032	            case FMT_RA_VS:
1033	            case FMT_RA_VS_M:
1034	                TALLY_INSTRUCTION(vector_inst);
1035	
1036	                // Vector/Scalar operation
1037	                // Pack compare results in low 16 bits of scalar register
1038	                uint32_t scalar_value = thread->scalar_reg[op2reg];
1039	                for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1040	                {
1041	                    result >>= 1;
1042	                    result |= scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1043	                                                   scalar_value) ? 0x8000 : 0;
1044	                }
1045	
1046	                break;
1047	
1048	            case FMT_RA_VV:
1049	            case FMT_RA_VV_M:
1050	                TALLY_INSTRUCTION(vector_inst);
1051	
1052	                // Vector/Vector operation
1053	                // Pack compare results in low 16 bits of scalar register
1054	                for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1055	                {
1056	                    result >>= 1;
1057	                    result |= scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1058	                                                   thread->vector_reg[op2reg][lane]) ? 0x8000 : 0;
1059	                }
1060	
1061	                break;
1062	
1063	            default:
1064	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1065	                return;
1066	        }
1067	
1068	        set_scalar_reg(thread, destreg, result);
1069	    }
1070	    else if (fmt == FMT_RA_SS)
1071	    {
1072	        uint32_t result = scalar_arithmetic_op(op, thread->scalar_reg[op1reg],
1073	                                               thread->scalar_reg[op2reg]);
1074	        set_scalar_reg(thread, destreg, result);
1075	    }
1076	    else
1077	    {
1078	        // Vector arithmetic
1079	        uint32_t result[NUM_VECTOR_LANES];
1080	        uint32_t mask;
1081	
1082	        TALLY_INSTRUCTION(vector_inst);
1083	        switch (fmt)
1084	        {
1085	            case FMT_RA_VS_M:
1086	            case FMT_RA_VV_M:
1087	                mask = thread->scalar_reg[maskreg];
1088	                break;
1089	
1090	            case FMT_RA_VS:
1091	            case FMT_RA_VV:
1092	                mask = 0xffff;
1093	                break;
1094	
1095	            default:
1096	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1097	                return;
1098	        }
1099	
1100	        if (op == OP_SHUFFLE)
1101	        {
1102	            const uint32_t *src1 = thread->vector_reg[op1reg];
1103	            const uint32_t *src2 = thread->vector_reg[op2reg];
1104	
1105	            for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1106	                result[lane] = src1[src2[lane] & 0xf];
1107	        }
1108	        else if (fmt == FMT_RA_VS || fmt == FMT_RA_VS_M)
1109	        {
1110	            // Vector/Scalar operands
1111	            uint32_t scalar_value = thread->scalar_reg[op2reg];
1112	            for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1113	            {
1114	                result[lane] = scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1115	                                                    scalar_value);
1116	            }
1117	        }
1118	        else
1119	        {
1120	            // Vector/Vector operands
1121	            for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1122	            {
1123	                result[lane] = scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1124	                                                    thread->vector_reg[op2reg][lane]);
1125	            }
1126	        }
1127	
1128	        set_vector_reg(thread, destreg, mask, result);
1129	    }
1130	}
1131	
1132	static void execute_immediate_arith_inst(struct thread *thread, uint32_t instruction)
1133	{
1134	    enum immediate_arith_format fmt = extract_unsigned_bits(instruction, 29, 2);
1135	    uint32_t imm_value;
1136	    enum arithmetic_op op = extract_unsigned_bits(instruction, 24, 5);
1137	    uint32_t op1reg = extract_unsigned_bits(instruction, 0, 5);
1138	    uint32_t maskreg = extract_unsigned_bits(instruction, 10, 5);
1139	    uint32_t destreg = extract_unsigned_bits(instruction, 5, 5);
1140	    int lane;
1141	
1142	    TALLY_INSTRUCTION(imm_arith_inst);
1143	    switch (fmt) {
1144	        case FMT_IMM_VM:
1145	            imm_value = extract_signed_bits(instruction, 15, 9);
1146	            break;
1147	
1148	        case FMT_IMM_MOVEHI:
1149	            imm_value = (extract_unsigned_bits(instruction, 10, 14) << 18)
1150	                | (extract_unsigned_bits(instruction, 0, 5) << 13);
1151	            break;
1152	
1153	        default:
1154	            imm_value = extract_signed_bits(instruction, 10, 14);
1155	            break;
1156	    }
1157	
1158	    if (op == OP_SYSCALL)
1159	    {
1160	        raise_trap(thread, 0, TT_SYSCALL, false, false,
1161	            extract_unsigned_bits(instruction, 10, 14));
1162	        return;
1163	    }
1164	    else if (op == OP_GETLANE)
1165	    {
1166	        TALLY_INSTRUCTION(vector_inst);
1167	        set_scalar_reg(thread, destreg, thread->vector_reg[op1reg][imm_value & 0xf]);
1168	    }
1169	    else if (is_compare_op(op))
1170	    {
1171	        uint32_t result = 0;
1172	        switch (fmt)
1173	        {
1174	            case FMT_IMM_V:
1175	            case FMT_IMM_VM:
1176	                TALLY_INSTRUCTION(vector_inst);
1177	
1178	                // Pack compare results into low 16 bits of scalar register
1179	                for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1180	                {
1181	                    result >>= 1;
1182	                    result |= scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1183	                                                   imm_value) ? 0x8000 : 0;
1184	                }
1185	
1186	                break;
1187	
1188	            case FMT_IMM_S:
1189	                result = scalar_arithmetic_op(op, thread->scalar_reg[op1reg],
1190	                                              imm_value) ? 0xffff : 0;
1191	                break;
1192	
1193	            default:
1194	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1195	                return;
1196	        }
1197	
1198	        set_scalar_reg(thread, destreg, result);
1199	    }
1200	    else if (fmt == FMT_IMM_S || fmt == FMT_IMM_MOVEHI)
1201	    {
1202	        uint32_t result = scalar_arithmetic_op(op, thread->scalar_reg[op1reg],
1203	                                               imm_value);
1204	        set_scalar_reg(thread, destreg, result);
1205	    }
1206	    else
1207	    {
1208	        // Vector arithmetic
1209	        uint32_t result[NUM_VECTOR_LANES];
1210	        uint32_t mask;
1211	
1212	        TALLY_INSTRUCTION(vector_inst);
1213	        switch (fmt)
1214	        {
1215	            case FMT_IMM_VM:
1216	                mask = thread->scalar_reg[maskreg];
1217	                break;
1218	
1219	            case FMT_IMM_V:
1220	                mask = 0xffff;
1221	                break;
1222	
1223	            default:
1224	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1225	                return;
1226	        }
1227	
1228	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1229	        {
1230	            result[lane] = scalar_arithmetic_op(op, thread->vector_reg[op1reg][lane],
1231	                                                imm_value);
1232	        }
1233	
1234	        set_vector_reg(thread, destreg, mask, result);
1235	    }
1236	}
