1238	static void execute_scalar_load_store_inst(struct thread *thread, uint32_t instruction)
1239	{
1240	    enum memory_op op = extract_unsigned_bits(instruction, 25, 4);
1241	    uint32_t ptrreg = extract_unsigned_bits(instruction, 0, 5);
1242	    uint32_t offset = extract_signed_bits(instruction, 10, 15);
1243	    uint32_t destsrcreg = extract_unsigned_bits(instruction, 5, 5);
1244	    bool is_load = extract_unsigned_bits(instruction, 29, 1);
1245	    uint32_t virtual_address;
1246	    uint32_t physical_address;
1247	    int is_device_access;
1248	    uint32_t value;
1249	    uint32_t access_size;
1250	
1251	    virtual_address = thread->scalar_reg[ptrreg] + offset;
1252	
1253	    switch (op)
1254	    {
1255	        case MEM_BYTE:
1256	        case MEM_BYTE_SEXT:
1257	            access_size = 1;
1258	            break;
1259	
1260	        case MEM_SHORT:
1261	        case MEM_SHORT_EXT:
1262	            access_size = 2;
1263	            break;
1264	
1265	        default:
1266	            access_size = 4;
1267	    }
1268	
1269	    // Check alignment
1270	    if ((virtual_address % access_size) != 0)
1271	    {
1272	        raise_trap(thread, virtual_address, TT_UNALIGNED_ACCESS, !is_load,
1273	            true, 0);
1274	        return;
1275	    }
1276	
1277	    if (!translate_address(thread, virtual_address, &physical_address, !is_load, true))
1278	        return; // fault raised, bypass other side effects
1279	
1280	    is_device_access = physical_address >= DEVICE_BASE_ADDRESS;
1281	    if (is_device_access && op != MEM_LONG)
1282	    {
1283	        // This is not an actual CPU fault, but a debugging aid in the emulator.
1284	        printf("%s Invalid device access %08x, pc %08x\n", is_load ? "Load" : "Store",
1285	               virtual_address, thread->pc - 4);
1286	        print_thread_registers(thread);
1287	        thread->core->proc->crashed = true;
1288	        return;
1289	    }
1290	
1291	    if (is_load)
1292	    {
1293	        switch (op)
1294	        {
1295	            case MEM_LONG:
1296	                if (is_device_access)
1297	                    value = read_device_register(physical_address);
1298	                else
1299	                    value = (uint32_t) *UINT32_PTR(thread->core->proc->memory, physical_address);
1300	
1301	                break;
1302	
1303	            case MEM_BYTE:
1304	                value = (uint32_t) *UINT8_PTR(thread->core->proc->memory, physical_address);
1305	                break;
1306	
1307	            case MEM_BYTE_SEXT:
1308	                value = (uint32_t)(int32_t) *INT8_PTR(thread->core->proc->memory, physical_address);
1309	                break;
1310	
1311	            case MEM_SHORT:
1312	                value = (uint32_t) *UINT16_PTR(thread->core->proc->memory, physical_address);
1313	                break;
1314	
1315	            case MEM_SHORT_EXT:
1316	                value = (uint32_t)(int32_t) *INT16_PTR(thread->core->proc->memory, physical_address);
1317	                break;
1318	
1319	            case MEM_SYNC:
1320	                value = *UINT32_PTR(thread->core->proc->memory, physical_address);
1321	                thread->last_sync_load_addr = physical_address / CACHE_LINE_LENGTH;
1322	                break;
1323	
1324	            case MEM_CONTROL_REG:
1325	                assert(0);	// Should have been handled in caller
1326	                return;
1327	
1328	            default:
1329	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1330	                return;
1331	        }
1332	
1333	        set_scalar_reg(thread, destsrcreg, value);
1334	    }
1335	    else
1336	    {
1337	        // Store
1338	        uint32_t value_to_store = thread->scalar_reg[destsrcreg];
1339	
1340	        // Some instruction don't update memory, for example: a synchronized store
1341	        // that fails or writes to device memory. This tracks whether they
1342	        // did for the cosimulation code below.
1343	        bool did_write = false;
1344	        switch (op)
1345	        {
1346	            case MEM_BYTE:
1347	            case MEM_BYTE_SEXT:
1348	                *UINT8_PTR(thread->core->proc->memory, physical_address) = (uint8_t) value_to_store;
1349	                did_write = true;
1350	                break;
1351	
1352	            case MEM_SHORT:
1353	            case MEM_SHORT_EXT:
1354	                *UINT16_PTR(thread->core->proc->memory, physical_address) = (uint16_t) value_to_store;
1355	                did_write = true;
1356	                break;
1357	
1358	            case MEM_LONG:
1359	                if (physical_address >= DEVICE_BASE_ADDRESS)
1360	                {
1361	                    // IO address range
1362	                    if (physical_address == REG_TIMER_INT)
1363	                        thread->core->proc->current_timer_count = value_to_store;
1364	                    else
1365	                        write_device_register(physical_address, value_to_store);
1366	
1367	                    // Bail to avoid logging and other side effects below.
1368	                    return;
1369	                }
1370	
1371	                *UINT32_PTR(thread->core->proc->memory, physical_address) = value_to_store;
1372	                did_write = true;
1373	                break;
1374	
1375	            case MEM_SYNC:
1376	                if (physical_address / CACHE_LINE_LENGTH == thread->last_sync_load_addr)
1377	                {
1378	                    // Success
1379	
1380	                    // HACK: cosim can only track one side effect per instruction, but sync
1381	                    // store has two: setting the register to indicate success and updating
1382	                    // memory. This only logs the memory transaction. Instead of
1383	                    // calling set_scalar_reg (which would log the register transfer as
1384	                    // a side effect), set the value explicitly here.
1385	                    thread->scalar_reg[destsrcreg] = 1;
1386	
1387	                    *UINT32_PTR(thread->core->proc->memory, physical_address) = value_to_store;
1388	                    did_write = true;
1389	                }
1390	                else
1391	                    thread->scalar_reg[destsrcreg] = 0;	// Fail. Set register manually as above.
1392	
1393	                break;
1394	
1395	            case MEM_CONTROL_REG:
1396	                assert(0);	// Should have been handled in caller
1397	                return;
1398	
1399	            default:
1400	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1401	                return;
1402	        }
1403	
1404	        if (did_write)
1405	        {
1406	            invalidate_sync_address(thread->core, physical_address);
1407	            if (thread->core->proc->enable_tracing)
1408	            {
1409	                printf("%08x [th %u] memory store size %u %08x %02x\n", thread->pc - 4,
1410	                       thread->id, access_size, virtual_address, value_to_store);
1411	            }
1412	
1413	            if (thread->core->proc->enable_cosim)
1414	            {
1415	                cosim_check_scalar_store(thread->core->proc, thread->pc - 4, virtual_address, access_size,
1416	                                         value_to_store);
1417	            }
1418	        }
1419	    }
1420	}
1421	
1422	static void execute_block_load_store_inst(struct thread *thread, uint32_t instruction)
1423	{
1424	    uint32_t op = extract_unsigned_bits(instruction, 25, 4);
1425	    uint32_t ptrreg = extract_unsigned_bits(instruction, 0, 5);
1426	    uint32_t maskreg = extract_unsigned_bits(instruction, 10, 5);
1427	    uint32_t destsrcreg = extract_unsigned_bits(instruction, 5, 5);
1428	    bool is_load = extract_unsigned_bits(instruction, 29, 1);
1429	    uint32_t offset;
1430	    uint32_t lane;
1431	    uint32_t mask;
1432	    uint32_t virtual_address;
1433	    uint32_t physical_address;
1434	    uint32_t *block_ptr;
1435	
1436	    TALLY_INSTRUCTION(vector_inst);
1437	
1438	    // Compute mask value
1439	    switch (op)
1440	    {
1441	        case MEM_BLOCK_VECTOR:
1442	            mask = 0xffff;
1443	            offset = extract_signed_bits(instruction, 10, 15);
1444	            break;
1445	
1446	        case MEM_BLOCK_VECTOR_MASK:
1447	            mask = thread->scalar_reg[maskreg];
1448	            offset = extract_signed_bits(instruction, 15, 10);
1449	            break;
1450	
1451	        default:
1452	            assert(0);
1453	    }
1454	
1455	    virtual_address = thread->scalar_reg[ptrreg] + offset;
1456	
1457	    // Check alignment
1458	    if ((virtual_address & (NUM_VECTOR_LANES * 4 - 1)) != 0)
1459	    {
1460	        raise_trap(thread, virtual_address, TT_UNALIGNED_ACCESS, !is_load,
1461	                   true, 0);
1462	        return;
1463	    }
1464	
1465	    if (!translate_address(thread, virtual_address, &physical_address, !is_load, true))
1466	        return; // fault raised, bypass other side effects
1467	
1468	    if (physical_address >= DEVICE_BASE_ADDRESS)
1469	    {
1470	        printf("Illegal block access to device address\n");
1471	        print_thread_registers(thread);
1472	        thread->core->proc->crashed = true;
1473	        return;
1474	    }
1475	
1476	    block_ptr = UINT32_PTR(thread->core->proc->memory, physical_address);
1477	    if (is_load)
1478	    {
1479	        uint32_t load_value[NUM_VECTOR_LANES];
1480	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1481	            load_value[lane] = block_ptr[lane];
1482	
1483	        set_vector_reg(thread, destsrcreg, mask, load_value);
1484	    }
1485	    else
1486	    {
1487	        uint32_t *store_value = thread->vector_reg[destsrcreg];
1488	
1489	        if ((mask & 0xffff) == 0)
1490	            return;	// Hardware ignores block stores with a mask of zero
1491	
1492	        if (thread->core->proc->enable_tracing)
1493	        {
1494	            printf("%08x [th %u] write_mem_block %08x\n", thread->pc - 4, thread->id,
1495	                   virtual_address);
1496	        }
1497	
1498	        if (thread->core->proc->enable_cosim)
1499	            cosim_check_vector_store(thread->core->proc, thread->pc - 4, virtual_address, mask, store_value);
1500	
1501	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
1502	        {
1503	            if (mask & (1 << lane))
1504	                block_ptr[lane] = store_value[lane];
1505	        }
1506	
1507	        invalidate_sync_address(thread->core, physical_address);
1508	    }
1509	}
