1511	static void execute_scatter_gather_inst(struct thread *thread, uint32_t instruction)
1512	{
1513	    uint32_t op = extract_unsigned_bits(instruction, 25, 4);
1514	    uint32_t ptrreg = extract_unsigned_bits(instruction, 0, 5);
1515	    uint32_t maskreg = extract_unsigned_bits(instruction, 10, 5);
1516	    uint32_t destsrcreg = extract_unsigned_bits(instruction, 5, 5);
1517	    bool is_load = extract_unsigned_bits(instruction, 29, 1);
1518	    uint32_t offset;
1519	    uint32_t lane;
1520	    uint32_t mask;
1521	    uint32_t virtual_address;
1522	    uint32_t physical_address;
1523	
1524	    TALLY_INSTRUCTION(vector_inst);
1525	
1526	    // Compute mask value
1527	    switch (op)
1528	    {
1529	        case MEM_SCGATH:
1530	            mask = 0xffff;
1531	            offset = extract_signed_bits(instruction, 10, 15);
1532	            break;
1533	
1534	        case MEM_SCGATH_MASK:
1535	            mask = thread->scalar_reg[maskreg];
1536	            offset = extract_signed_bits(instruction, 15, 10);
1537	            break;
1538	
1539	        default:
1540	            assert(0);
1541	    }
1542	
1543	    lane = thread->subcycle;
1544	    virtual_address = thread->vector_reg[ptrreg][lane] + offset;
1545	    if ((mask & (1 << lane)) && (virtual_address & 3) != 0)
1546	    {
1547	        raise_trap(thread, virtual_address, TT_UNALIGNED_ACCESS, !is_load,
1548	            true, 0);
1549	        return;
1550	    }
1551	
1552	    if (!translate_address(thread, virtual_address, &physical_address, !is_load, true))
1553	        return; // fault raised, bypass other side effects
1554	
1555	    if (physical_address >= DEVICE_BASE_ADDRESS)
1556	    {
1557	        printf("Illegal scatter access to device address\n");
1558	        print_thread_registers(thread);
1559	        thread->core->proc->crashed = true;
1560	        return;
1561	    }
1562	
1563	    if (is_load)
1564	    {
1565	        uint32_t load_value[NUM_VECTOR_LANES];
1566	        memset(load_value, 0, NUM_VECTOR_LANES * sizeof(uint32_t));
1567	        if (mask & (1 << lane))
1568	            load_value[lane] = *UINT32_PTR(thread->core->proc->memory, physical_address);
1569	
1570	        set_vector_reg(thread, destsrcreg, mask & (1 << lane), load_value);
1571	    }
1572	    else if (mask & (1 << lane))
1573	    {
1574	        if (thread->core->proc->enable_tracing)
1575	        {
1576	            printf("%08x [th %u] store_scatter (%u) %08x %08x\n", thread->pc - 4,
1577	                   thread->id, thread->subcycle, virtual_address,
1578	                   thread->vector_reg[destsrcreg][lane]);
1579	        }
1580	
1581	        *UINT32_PTR(thread->core->proc->memory, physical_address)
1582	            = thread->vector_reg[destsrcreg][lane];
1583	        invalidate_sync_address(thread->core, physical_address);
1584	        if (thread->core->proc->enable_cosim)
1585	        {
1586	            cosim_check_scalar_store(thread->core->proc, thread->pc - 4, virtual_address, 4,
1587	                                     thread->vector_reg[destsrcreg][lane]);
1588	        }
1589	    }
1590	
1591	    if (++thread->subcycle == NUM_VECTOR_LANES)
1592	        thread->subcycle = 0; // Finish
1593	    else
1594	        thread->pc -= 4;	// repeat current instruction
1595	}
1596	
1597	static void execute_control_register_inst(struct thread *thread, uint32_t instruction)
1598	{
1599	    uint32_t cr_index = extract_unsigned_bits(instruction, 0, 5);
1600	    uint32_t dst_src_reg = extract_unsigned_bits(instruction, 5, 5);
1601	
1602	    // Only threads in supervisor mode can access control registers.
1603	    if (!thread->enable_supervisor)
1604	    {
1605	        raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
1606	        return;
1607	    }
1608	
1609	    if (extract_unsigned_bits(instruction, 29, 1))
1610	        read_control_register(thread, cr_index, dst_src_reg);
1611	    else
1612	        write_control_register(thread, cr_index, dst_src_reg);
1613	}
1614	
1615	static void read_control_register(struct thread *thread, uint32_t cr_index,
1616	                                  uint32_t dst_src_reg)
1617	{
1618	    uint32_t value = 0xffffffff;
1619	
1620	    switch (cr_index)
1621	    {
1622	        case CR_THREAD_ID:
1623	            value = thread->id;
1624	            break;
1625	
1626	        case CR_TRAP_HANDLER:
1627	            value = thread->core->trap_handler_pc;
1628	            break;
1629	
1630	        case CR_TRAP_PC:
1631	            value = thread->saved_trap_state[0].pc;
1632	            break;
1633	
1634	        case CR_TRAP_REASON:
1635	            value = thread->saved_trap_state[0].trap_cause;
1636	            break;
1637	
1638	        case CR_FLAGS:
1639	            value = (thread->enable_interrupt ? 1 : 0)
1640	                    | (thread->enable_mmu ? 2 : 0)
1641	                    | (thread->enable_supervisor ? 4 : 0);
1642	            break;
1643	
1644	        case CR_SAVED_FLAGS:
1645	            value = (thread->saved_trap_state[0].enable_interrupt ? 1 : 0)
1646	                    | (thread->saved_trap_state[0].enable_mmu ? 2 : 0)
1647	                    | (thread->saved_trap_state[0].enable_supervisor ? 4 : 0);
1648	            break;
1649	
1650	        case CR_CURRENT_ASID:
1651	            value = thread->asid;
1652	            break;
1653	
1654	        case CR_PAGE_DIR:
1655	            value = thread->page_dir;
1656	            break;
1657	
1658	        case CR_TRAP_ACCESS_ADDR:
1659	            value = thread->saved_trap_state[0].access_address;
1660	            break;
1661	
1662	        case CR_CYCLE_COUNT:
1663	            value = (uint32_t) thread->core->proc->total_instructions;
1664	            break;
1665	
1666	        case CR_TLB_MISS_HANDLER:
1667	            value = thread->core->tlb_miss_handler_pc;
1668	            break;
1669	
1670	        case CR_SCRATCHPAD0:
1671	            value = thread->saved_trap_state[0].scratchpad0;
1672	            break;
1673	
1674	        case CR_SCRATCHPAD1:
1675	            value = thread->saved_trap_state[0].scratchpad1;
1676	            break;
1677	
1678	        case CR_SUBCYCLE:
1679	            value = thread->saved_trap_state[0].subcycle;
1680	            break;
1681	
1682	        case CR_INTERRUPT_PENDING:
1683	            value = get_pending_interrupts(thread) & thread->interrupt_mask;
1684	            break;
1685	
1686	        case CR_INTERRUPT_ENABLE:
1687	            value = thread->interrupt_mask;
1688	            break;
1689	
1690	        case CR_INTERRUPT_TRIGGER:
1691	            value = thread->core->is_level_triggered;
1692	            break;
1693	
1694	        case CR_SYSCALL_INDEX:
1695	            value = thread->saved_trap_state[0].syscall_index;
1696	            break;
1697	    }
1698	
1699	    set_scalar_reg(thread, dst_src_reg, value);
1700	}
1701	
1702	static void write_control_register(struct thread *thread, uint32_t cr_index,
1703	                                   uint32_t dst_src_reg)
1704	{
1705	    uint32_t value = thread->scalar_reg[dst_src_reg];
1706	    switch (cr_index)
1707	    {
1708	        case CR_TRAP_HANDLER:
1709	            thread->core->trap_handler_pc = value;
1710	            break;
1711	
1712	        case CR_TRAP_PC:
1713	            thread->saved_trap_state[0].pc = value;
1714	            break;
1715	
1716	        case CR_FLAGS:
1717	            thread->enable_interrupt = (value & 1) != 0;
1718	            thread->enable_mmu = (value & 2) != 0;
1719	            thread->enable_supervisor = (value & 4) != 0;
1720	
1721	            // An interrupt may have occurred while interrupts were
1722	            // disabled.
1723	            if (thread->enable_interrupt)
1724	                try_to_dispatch_interrupt(thread);
1725	
1726	            break;
1727	
1728	        case CR_SAVED_FLAGS:
1729	            thread->saved_trap_state[0].enable_interrupt = (value & 1) != 0;
1730	            thread->saved_trap_state[0].enable_mmu = (value & 2) != 0;
1731	            thread->saved_trap_state[0].enable_supervisor = (value & 4) != 0;
1732	            break;
1733	
1734	        case CR_CURRENT_ASID:
1735	            thread->asid = value;
1736	            break;
1737	
1738	        case CR_PAGE_DIR:
1739	            thread->page_dir = value;
1740	            break;
1741	
1742	        case CR_TLB_MISS_HANDLER:
1743	            thread->core->tlb_miss_handler_pc = value;
1744	            break;
1745	
1746	        case CR_SCRATCHPAD0:
1747	            thread->saved_trap_state[0].scratchpad0 = value;
1748	            break;
1749	
1750	        case CR_SCRATCHPAD1:
1751	            thread->saved_trap_state[0].scratchpad1 = value;
1752	            break;
1753	
1754	        case CR_SUBCYCLE:
1755	            thread->saved_trap_state[0].subcycle = value;
1756	            break;
1757	
1758	        case CR_INTERRUPT_ENABLE:
1759	            thread->interrupt_mask = value;
1760	            break;
1761	
1762	        case CR_INTERRUPT_ACK:
1763	            thread->latched_interrupts &= ~value;
1764	            break;
1765	
1766	        case CR_INTERRUPT_TRIGGER:
1767	            thread->core->is_level_triggered = value;
1768	            break;
1769	
1770	        case CR_SUSPEND_THREAD:
1771	            thread->core->proc->thread_enable_mask &= ~value;
1772	            break;
1773	
1774	        case CR_RESUME_THREAD:
1775	            thread->core->proc->thread_enable_mask |= value
1776	                & ((1ull << thread->core->proc->total_threads) - 1);
1777	            break;
1778	    }
1779	}
1780	
1781	static void execute_memory_access_inst(struct thread *thread, uint32_t instruction)
1782	{
1783	    uint32_t type = extract_unsigned_bits(instruction, 25, 4);
1784	    if (type != MEM_CONTROL_REG)	// Don't count control register transfers
1785	    {
1786	        if (extract_unsigned_bits(instruction, 29, 1))
1787	            TALLY_INSTRUCTION(load_inst);
1788	        else
1789	            TALLY_INSTRUCTION(store_inst);
1790	    }
1791	
1792	    switch (type)
1793	    {
1794	        case MEM_BYTE:
1795	        case MEM_BYTE_SEXT:
1796	        case MEM_SHORT:
1797	        case MEM_SHORT_EXT:
1798	        case MEM_LONG:
1799	        case MEM_SYNC:
1800	            execute_scalar_load_store_inst(thread, instruction);
1801	            break;
1802	
1803	        case MEM_CONTROL_REG:
1804	            execute_control_register_inst(thread, instruction);
1805	            break;
1806	
1807	        case MEM_BLOCK_VECTOR:
1808	        case MEM_BLOCK_VECTOR_MASK:
1809	            execute_block_load_store_inst(thread, instruction);
1810	            break;
1811	
1812	        case MEM_SCGATH:
1813	        case MEM_SCGATH_MASK:
1814	            execute_scatter_gather_inst(thread, instruction);
1815	            break;
1816	
1817	        default:
1818	            raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1819	    }
1820	}
1821	
1822	static void execute_branch_inst(struct thread *thread, uint32_t instruction)
1823	{
1824	    uint32_t src_reg = extract_unsigned_bits(instruction, 0, 5);
1825	
1826	    // Subtract 4 because PC was already incremented after fetching instruction
1827	    uint32_t offset20 = extract_signed_bits(instruction, 5, 20) * 4 - 4;
1828	    uint32_t offset25 = extract_signed_bits(instruction, 0, 25) * 4 - 4;
1829	
1830	    TALLY_INSTRUCTION(branch_inst);
1831	    switch (extract_unsigned_bits(instruction, 25, 3))
1832	    {
1833	        case BRANCH_REGISTER:
1834	            thread->pc = thread->scalar_reg[src_reg];
1835	            break;
1836	
1837	        case BRANCH_ZERO:
1838	            if (thread->scalar_reg[src_reg] == 0)
1839	                thread->pc += offset20;
1840	
1841	            break;
1842	
1843	        case BRANCH_NOT_ZERO:
1844	            if (thread->scalar_reg[src_reg] != 0)
1845	                thread->pc += offset20;
1846	
1847	            break;
1848	
1849	        case BRANCH_ALWAYS:
1850	            thread->pc += offset25;
1851	            break;
1852	
1853	        case BRANCH_CALL_OFFSET:
1854	            set_scalar_reg(thread, LINK_REG, thread->pc);
1855	            thread->pc += offset25;
1856	            break;
1857	
1858	        case BRANCH_CALL_REGISTER:
1859	            set_scalar_reg(thread, LINK_REG, thread->pc);
1860	            thread->pc = thread->scalar_reg[src_reg];
1861	            break;
1862	
1863	        case BRANCH_ERET:
1864	            if (!thread->enable_supervisor)
1865	            {
1866	                raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
1867	                return;
1868	            }
1869	
1870	            thread->enable_interrupt = thread->saved_trap_state[0].enable_interrupt;
1871	            thread->enable_mmu = thread->saved_trap_state[0].enable_mmu;
1872	            thread->pc = thread->saved_trap_state[0].pc;
1873	            thread->subcycle = thread->saved_trap_state[0].subcycle;
1874	            thread->enable_supervisor = thread->saved_trap_state[0].enable_supervisor;
1875	
1876	            // Restore nested interrupt state
1877	            thread->saved_trap_state[0] = thread->saved_trap_state[1];
1878	
1879	            // There may be other interrupts pending
1880	            if (thread->enable_interrupt)
1881	                try_to_dispatch_interrupt(thread);
1882	
1883	            break;
1884	
1885	        default:
1886	            raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
1887	            break;
1888	    }
1889	}
1890	
1891	static void execute_cache_control_inst(struct thread *thread, uint32_t instruction)
1892	{
1893	    uint32_t op = extract_unsigned_bits(instruction, 25, 3);
1894	    uint32_t ptr_reg = extract_unsigned_bits(instruction, 0, 5);
1895	    uint32_t way;
1896	    bool updated_entry;
1897	
1898	    switch (op)
1899	    {
1900	        case CC_DINVALIDATE:
1901	            if (!thread->enable_supervisor)
1902	            {
1903	                raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
1904	                return;
1905	            }
1906	
1907	        // Falls through...
1908	
1909	        case CC_DFLUSH:
1910	        {
1911	            // This needs to fault if the TLB entry isn't present. translate_address
1912	            // will do that as a side effect.
1913	            uint32_t offset = extract_signed_bits(instruction, 15, 10);
1914	            uint32_t physical_address;
1915	            translate_address(thread, thread->scalar_reg[ptr_reg] + offset,
1916	                              &physical_address, false, true);
1917	            break;
1918	        }
1919	
1920	        case CC_DTLB_INSERT:
1921	        case CC_ITLB_INSERT:
1922	        {
1923	            uint32_t virtual_address = ROUND_TO_PAGE(thread->scalar_reg[ptr_reg]);
1924	            uint32_t phys_addr_reg = extract_unsigned_bits(instruction, 5, 5);
1925	            uint32_t phys_addr_and_flags = thread->scalar_reg[phys_addr_reg];
1926	            uint32_t *way_ptr;
1927	            struct tlb_entry *tlb;
1928	
1929	            if (!thread->enable_supervisor)
1930	            {
1931	                raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
1932	                return;
1933	            }
1934	
1935	            if (op == CC_DTLB_INSERT)
1936	            {
1937	                tlb = thread->core->dtlb;
1938	                way_ptr = &thread->core->next_dtlb_way;
1939	            }
1940	            else
1941	            {
1942	                tlb = thread->core->itlb;
1943	                way_ptr = &thread->core->next_itlb_way;
1944	            }
1945	
1946	            struct tlb_entry *entry = &tlb[((virtual_address / PAGE_SIZE) % TLB_SETS) * TLB_WAYS];
1947	            updated_entry = false;
1948	            for (way = 0; way < TLB_WAYS; way++)
1949	            {
1950	                if (entry[way].virtual_address == virtual_address
1951	                        && ((entry[way].phys_addr_and_flags & TLB_GLOBAL) != 0
1952	                            || entry[way].asid == thread->asid))
1953	                {
1954	                    // Found existing entry, update it
1955	                    entry[way].phys_addr_and_flags = phys_addr_and_flags;
1956	                    updated_entry = true;
1957	                    break;
1958	                }
1959	            }
1960	
1961	            if (!updated_entry)
1962	            {
1963	                // Replace entry with a new one
1964	                entry[*way_ptr].virtual_address = virtual_address;
1965	                entry[*way_ptr].phys_addr_and_flags = phys_addr_and_flags;
1966	                entry[*way_ptr].asid = thread->asid;
1967	            }
1968	
1969	            *way_ptr = (*way_ptr + 1) % TLB_WAYS;
1970	            break;
1971	        }
1972	
1973	        case CC_INVALIDATE_TLB:
1974	        {
1975	            uint32_t offset = extract_signed_bits(instruction, 15, 10);
1976	            uint32_t virtual_address = ROUND_TO_PAGE(thread->scalar_reg[ptr_reg] + offset);
1977	            uint32_t tlb_index = ((virtual_address / PAGE_SIZE) % TLB_SETS) * TLB_WAYS;
1978	
1979	            if (!thread->enable_supervisor)
1980	            {
1981	                raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
1982	                return;
1983	            }
1984	
1985	            for (way = 0; way < TLB_WAYS; way++)
1986	            {
1987	                if (thread->core->itlb[tlb_index + way].virtual_address == virtual_address)
1988	                    thread->core->itlb[tlb_index + way].virtual_address = INVALID_ADDR;
1989	
1990	                if (thread->core->dtlb[tlb_index + way].virtual_address == virtual_address)
1991	                    thread->core->dtlb[tlb_index + way].virtual_address = INVALID_ADDR;
1992	            }
1993	
1994	            break;
1995	        }
1996	
1997	        case CC_INVALIDATE_TLB_ALL:
1998	        {
1999	            int i;
2000	
2001	            if (!thread->enable_supervisor)
2002	            {
2003	                raise_trap(thread, 0, TT_PRIVILEGED_OP, false, false, 0);
2004	                return;
2005	            }
2006	
2007	            for (i = 0; i < TLB_SETS * TLB_WAYS; i++)
2008	            {
2009	                // Set to invalid (unaligned) addresses so these don't match
2010	                thread->core->itlb[i].virtual_address = INVALID_ADDR;
2011	                thread->core->dtlb[i].virtual_address = INVALID_ADDR;
2012	            }
2013	
2014	            break;
2015	        }
2016	    }
2017	}
2018	
2019	static bool execute_instruction(struct thread *thread)
2020	{
2021	    uint32_t instruction;
2022	    uint32_t physical_pc;
2023	    unsigned int fetch_pc = thread->pc;
2024	    thread->pc += 4;
2025	
2026	    // Check PC alignment
2027	    if ((fetch_pc & 3) != 0)
2028	    {
2029	        raise_trap(thread, thread->pc, TT_UNALIGNED_ACCESS, false, false, 0);
2030	        return true;   // XXX if stop on fault was enabled, should return false
2031	    }
2032	
2033	    if (!translate_address(thread, fetch_pc, &physical_pc, false, false))
2034	        return true;	// On next execution will start in TLB miss handler
2035	
2036	    // XXX if stop on fault was enabled, should return false
2037	
2038	    instruction = *UINT32_PTR(thread->core->proc->memory, physical_pc);
2039	    thread->core->proc->total_instructions++;
2040	
2041	restart:
2042	    if ((instruction & 0xe0000000) == 0xc0000000)
2043	        execute_register_arith_inst(thread, instruction);
2044	    else if ((instruction & 0x80000000) == 0)
2045	    {
2046	        if (instruction == BREAKPOINT_INST)
2047	        {
2048	            struct breakpoint *breakpoint = lookup_breakpoint(thread->core->proc, thread->pc - 4);
2049	            if (breakpoint == NULL)
2050	            {
2051	                // We use a special instruction (which is invalid) to trigger
2052	                // breakpoint lookup. This is an optimization to avoid doing
2053	                // a lookup on every instruction. In this case, the special
2054	                // instruction was already in the program, so raise a fault.
2055	                raise_trap(thread, 0, TT_ILLEGAL_INSTRUCTION, false, false, 0);
2056	                return true;
2057	            }
2058	
2059	            // The restart flag indicates we must step past a breakpoint we
2060	            // just hit. Substitute the original instruction.
2061	            if (breakpoint->restart || thread->core->proc->single_stepping)
2062	            {
2063	                breakpoint->restart = false;
2064	                instruction = breakpoint->original_instruction;
2065	                assert(instruction != BREAKPOINT_INST);
2066	                goto restart;
2067	            }
2068	            else
2069	            {
2070	                // Hit a breakpoint
2071	                breakpoint->restart = true;
2072	                thread->pc -= 4;    // Reset PC to instruction that trapped.
2073	                return false;
2074	            }
2075	        }
2076	        else if (instruction != INSTRUCTION_NOP)
2077	        {
2078	            // Don't call this for nop instructions. Although executing
2079	            // the instruction (or s0, s0, s0) has no effect, it would
2080	            // cause a cosimulation mismatch because the verilog model
2081	            // does not generate an event for it.
2082	
2083	            execute_immediate_arith_inst(thread, instruction);
2084	        }
2085	    }
2086	    else if ((instruction & 0xc0000000) == 0x80000000)
2087	        execute_memory_access_inst(thread, instruction);
2088	    else if ((instruction & 0xf0000000) == 0xf0000000)
2089	        execute_branch_inst(thread, instruction);
2090	    else if ((instruction & 0xf0000000) == 0xe0000000)
2091	        execute_cache_control_inst(thread, instruction);
2092	    else
2093	        printf("Bad instruction @%08x\n", thread->pc - 4);
2094	
2095	    return true;
2096	}
2097	
2098	static void timer_tick(struct processor *proc)
2099	{
2100	    if (proc->current_timer_count > 0)
2101	    {
2102	        if (proc->current_timer_count-- == 1)
2103	            raise_interrupt(proc, INT_TIMER);
2104	    }
2105	}
